import json
from pathlib import Path
from fastapi import FastAPI, HTTPException
from fastapi.responses import HTMLResponse

CONFIG_PATH = Path(__file__).resolve().parents[1] / "dpmp" / "config_v2.json"

app = FastAPI()

@app.get("/", response_class=HTMLResponse)
def home():
    return """
    <h1>DPMP v2 Config GUI</h1>
    <ul>
      <li><a href="/settings">Settings</a></li>
      <li><a href="/api/config">GET /api/config</a></li>
    </ul>
    """

@app.get("/settings", response_class=HTMLResponse)
def settings():
    return HTMLResponse(content='<!doctype html>\n<html>\n<head>\n  <meta charset="utf-8" />\n  <meta name="viewport" content="width=device-width,initial-scale=1" />\n  <title>DPMP v2 Settings</title>\n  <style>\n    body{font-family:system-ui,-apple-system,Segoe UI,Roboto,Arial;margin:0;background:#f3f4f6;}\n    .wrap{max-width:1100px;margin:0 auto;padding:24px;}\n    .top{display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;}\n    h1{font-size:22px;margin:0;}\n    .grid{display:grid;grid-template-columns:1fr;gap:14px;}\n    .card{background:#fff;border-radius:14px;box-shadow:0 1px 8px rgba(0,0,0,.08);padding:16px;}\n    .card h2{font-size:16px;margin:0 0 10px 0;}\n    .row{display:grid;grid-template-columns:220px 1fr;gap:12px;align-items:center;margin:10px 0;}\n    label{color:#374151;font-size:13px;}\n    input,select,textarea{width:100%;padding:10px;border:1px solid #d1d5db;border-radius:10px;font-size:14px;background:#fff;}\n    textarea{min-height:90px;font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;}\n    .btn{padding:10px 14px;border-radius:12px;border:0;background:#111827;color:#fff;font-weight:600;cursor:pointer;}\n    .btn:disabled{opacity:.5;cursor:not-allowed;}\n    .msg{font-size:13px;color:#111827;}\n    .small{font-size:12px;color:#6b7280;}\n  </style>\n</head>\n<body>\n  <div class="wrap">\n    <div class="top">\n      <h1>DPMP v2 Settings</h1>\n      <div>\n        <button id="reload" class="btn" type="button">Reload</button>\n        <button id="save" class="btn" type="button">Save</button>\n      </div>\n    </div>\n\n    <div class="grid">\n      <div class="card">\n        <h2>Listen</h2>\n        <div class="row"><label>Host</label><input id="listen_host" /></div>\n        <div class="row"><label>Port</label><input id="listen_port" type="number" /></div>\n        <div class="small">Miners connect here (Stratum v1).</div>\n      </div>\n\n      <div class="card">\n        <h2>Metrics</h2>\n        <div class="row"><label>Enabled</label>\n          <select id="metrics_enabled"><option value="true">true</option><option value="false">false</option></select>\n        </div>\n        <div class="row"><label>Host</label><input id="metrics_host" /></div>\n        <div class="row"><label>Port</label><input id="metrics_port" type="number" /></div>\n      </div>\n\n      <div class="card">\n        <h2>Pools</h2>\n        <div class="row"><label>Pool A host</label><input id="poolA_host" /></div>\n        <div class="row"><label>Pool A port</label><input id="poolA_port" type="number" /></div>\n        <div class="row"><label>Pool A name</label><input id="poolA_name" /></div>\n        <div class="row"><label>Pool A wallet</label><input id="poolA_wallet" /></div>\n        <hr/>\n        <div class="row"><label>Pool B host</label><input id="poolB_host" /></div>\n        <div class="row"><label>Pool B port</label><input id="poolB_port" type="number" /></div>\n        <div class="row"><label>Pool B name</label><input id="poolB_name" /></div>\n        <div class="row"><label>Pool B wallet</label><input id="poolB_wallet" /></div>\n      </div>\n\n      <div class="card">\n        <h2>Scheduler</h2>\n        <div class="row"><label>Mode</label><input id="sched_mode" /></div>\n        <div class="row"><label>Pool A weight</label><input id="sched_wA" type="number" /></div>\n        <div class="row"><label>Pool B weight</label><input id="sched_wB" type="number" /></div>\n        <div class="row"><label>Slice seconds</label><input id="sched_slice" type="number" /></div>\n        <div class="row"><label>Min switch seconds</label><input id="sched_minsw" type="number" /></div>\n      </div>\n\n      <div class="card">\n        <h2>Logging</h2>\n        <div class="row"><label>Level</label><input id="log_level" /></div>\n        <div class="row"><label>Allow (comma or list)</label><input id="log_allow" /></div>\n        <div class="row"><label>Deny (comma or list)</label><input id="log_deny" /></div>\n      </div>\n\n      <div class="card">\n        <h2>Downstream diff</h2>\n        <textarea id="downstream_diff"></textarea>\n        <div class="small">JSON object (advanced).</div>\n      </div>\n\n      <div class="card">\n        <div id="msg" class="msg"></div>\n      </div>\n    </div>\n  </div>\n\n<script>\nlet CURRENT = null;\n\nfunction $(id){ return document.getElementById(id); }\n\nfunction setMsg(t){ $("msg").textContent = t || ""; }\n\nfunction fill(cfg){\n  CURRENT = cfg;\n  $("listen_host").value = cfg.listen?.host ?? "";\n  $("listen_port").value = cfg.listen?.port ?? "";\n\n  $("metrics_enabled").value = String(cfg.metrics?.enabled ?? true);\n  $("metrics_host").value = cfg.metrics?.host ?? "";\n  $("metrics_port").value = cfg.metrics?.port ?? "";\n\n  $("poolA_host").value = cfg.pools?.A?.host ?? "";\n  $("poolA_port").value = cfg.pools?.A?.port ?? "";\n  $("poolA_name").value = cfg.pools?.A?.name ?? "A";\n  $("poolA_wallet").value = cfg.pools?.A?.wallet ?? "";\n\n  $("poolB_host").value = cfg.pools?.B?.host ?? "";\n  $("poolB_port").value = cfg.pools?.B?.port ?? "";\n  $("poolB_name").value = cfg.pools?.B?.name ?? "B";\n  $("poolB_wallet").value = cfg.pools?.B?.wallet ?? "";\n\n  $("sched_mode").value = cfg.scheduler?.mode ?? "ratio";\n  $("sched_wA").value = cfg.scheduler?.poolA_weight ?? 50;\n  $("sched_wB").value = cfg.scheduler?.poolB_weight ?? 50;\n  $("sched_slice").value = cfg.scheduler?.slice_seconds ?? 30;\n  $("sched_minsw").value = cfg.scheduler?.min_switch_seconds ?? 30;\n\n  $("log_level").value = cfg.logging?.level ?? "INFO";\n  $("log_allow").value = Array.isArray(cfg.logging?.allow) ? cfg.logging.allow.join(",") : (cfg.logging?.allow ?? "");\n  $("log_deny").value = Array.isArray(cfg.logging?.deny) ? cfg.logging.deny.join(",") : (cfg.logging?.deny ?? "");\n\n  $("downstream_diff").value = JSON.stringify(cfg.downstream_diff ?? {}, null, 2);\n}\n\nfunction readForm(){\n  const cfg = JSON.parse(JSON.stringify(CURRENT || {}));\n  cfg.listen = { host: $("listen_host").value.trim(), port: Number($("listen_port").value) };\n  cfg.metrics = { enabled: $("metrics_enabled").value === "true", host: $("metrics_host").value.trim(), port: Number($("metrics_port").value) };\n\n  cfg.pools = cfg.pools || {};\n  cfg.pools.A = { host: $("poolA_host").value.trim(), port: Number($("poolA_port").value), name: $("poolA_name").value.trim(), wallet: $("poolA_wallet").value.trim() };\n  cfg.pools.B = { host: $("poolB_host").value.trim(), port: Number($("poolB_port").value), name: $("poolB_name").value.trim(), wallet: $("poolB_wallet").value.trim() };\n\n  cfg.scheduler = { mode: $("sched_mode").value.trim(), poolA_weight: Number($("sched_wA").value), poolB_weight: Number($("sched_wB").value),\n                    slice_seconds: Number($("sched_slice").value), min_switch_seconds: Number($("sched_minsw").value) };\n\n  cfg.logging = cfg.logging || {};\n  cfg.logging.level = $("log_level").value.trim();\n  cfg.logging.allow = $("log_allow").value.trim() ? $("log_allow").value.split(",").map(x=>x.trim()).filter(Boolean) : [];\n  cfg.logging.deny  = $("log_deny").value.trim()  ? $("log_deny").value.split(",").map(x=>x.trim()).filter(Boolean)  : [];\n\n  try{\n    cfg.downstream_diff = JSON.parse($("downstream_diff").value || "{}");\n  }catch(e){\n    throw new Error("downstream_diff must be valid JSON");\n  }\n  return cfg;\n}\n\nasync function load(){\n  setMsg("Loading...");\n  const r = await fetch("/api/config");\n  if(!r.ok){ setMsg("Load failed: " + r.status); return; }\n  const cfg = await r.json();\n  fill(cfg);\n  setMsg("Loaded.");\n}\n\nasync function save(){\n  let cfg;\n  try{ cfg = readForm(); }catch(e){ setMsg("Save blocked: " + e.message); return; }\n  setMsg("Saving...");\n  const r = await fetch("/api/config", {method:"PUT", headers:{"Content-Type":"application/json"}, body: JSON.stringify(cfg)});\n  if(!r.ok){\n    const t = await r.text();\n    setMsg("Save failed: " + r.status + " " + t);\n    return;\n  }\n  setMsg("Saved. (Restart DPMP to apply)");\n}\n\n$("reload").onclick = load;\n$("save").onclick = save;\nload();\n</script>\n</body>\n</html>\n')

@app.get("/api/config")
def get_config():
    try:
        return json.loads(CONFIG_PATH.read_text(encoding="utf-8"))
    except FileNotFoundError:
        raise HTTPException(status_code=404, detail="config_v2.json not found")
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"read failed: {e}")

@app.put("/api/config")
def put_config(cfg: dict):
    # minimal safety: must be a dict and must contain top-level keys we expect
    if not isinstance(cfg, dict):
        raise HTTPException(status_code=400, detail="payload must be a JSON object")
    for k in ["listen", "metrics", "pools", "scheduler"]:
        if k not in cfg:
            raise HTTPException(status_code=400, detail=f"missing key: {k}")
    tmp = CONFIG_PATH.with_suffix(".json.tmp")
    tmp.write_text(json.dumps(cfg, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    tmp.replace(CONFIG_PATH)
    return {"ok": True}
